    use HandlesXmlTests;

    public static function setUpBeforeClass(): void
    {
        self::$document = InvoiceSuiteDocumentBuilder::createByProviderUniqueId('zffxcomfort');
    }

    public function testHasCurrentDocumentProvider(): void
    {
        $this->assertTrue(self::$document->hasCurrentDocumentFormatProvider());
        $this->assertSame('zffxcomfort', self::$document->getCurrentDocumentFormatProvider()->getUniqueId());
        $this->assertNotNull(self::$document->getCurrentDocumentFormatProvider()->getBuilder());
        $this->assertInstanceOf(InvoiceSuiteZfFxComfortProviderBuilder::class, self::$document->getCurrentDocumentFormatProvider()->getBuilder());
        $this->assertInstanceOf(InvoiceSuiteAbstractDocumentFormatBuilder::class, self::$document->getCurrentDocumentFormatProvider()->getBuilder());
        $this->assertNotNull(self::$document->getCurrentDocumentFormatProvider()->getBuilder()->getDocumentRootObject());
        $this->assertInstanceOf(CrossIndustryInvoice::class, self::$document->getCurrentDocumentFormatProvider()->getBuilder()->getDocumentRootObject());
    }

    public function testDocumentProfile(): void
    {
        $this->assertXPathNotExistsWithIndex('/rsm:CrossIndustryInvoice/rsm:ExchangedDocumentContext/ram:BusinessProcessSpecifiedDocumentContextParameter/ram:ID', 0);
        $this->assertXPathNotExistsWithIndex('/rsm:CrossIndustryInvoice/rsm:ExchangedDocumentContext/ram:BusinessProcessSpecifiedDocumentContextParameter/ram:ID', 1);
        $this->assertXPathValueWithIndex('/rsm:CrossIndustryInvoice/rsm:ExchangedDocumentContext/ram:GuidelineSpecifiedDocumentContextParameter/ram:ID', 0, 'urn:cen.eu:en16931:2017');
        $this->assertXPathNotExistsWithIndex('/rsm:CrossIndustryInvoice/rsm:ExchangedDocumentContext/ram:GuidelineSpecifiedDocumentContextParameter/ram:ID', 1);
    }
    public function testSetDocumentNo(): void
    {
        self::$document->setDocumentNo(null);

        $this->assertXPathNotExists('/rsm:CrossIndustryInvoice/rsm:ExchangedDocument/ram:ID');

        self::$document->setDocumentNo('');

        $this->assertXPathNotExists('/rsm:CrossIndustryInvoice/rsm:ExchangedDocument/ram:ID');

        self::$document->setDocumentNo("2025/08-000001");

        $this->assertXPathValue('/rsm:CrossIndustryInvoice/rsm:ExchangedDocument/ram:ID', "2025/08-000001");

        self::$document->setDocumentNo(null);

        $this->assertXPathNotExists('/rsm:CrossIndustryInvoice/rsm:ExchangedDocument/ram:ID');

        self::$document->setDocumentNo('');

        $this->assertXPathNotExists('/rsm:CrossIndustryInvoice/rsm:ExchangedDocument/ram:ID');
    }

