        $resolvedContentType = InvoiceSuiteContentTypeResolver::resolveContentType($jsonFileContent);

        $this->assertSame(InvoiceSuiteContentTypeResolver::JSON, $resolvedContentType);
    }

    public function testCopyToReader(): void
    {
