        $this->assertSame('zffxcomfort', $documentReader->getCurrentDocumentFormatProvider()->getUniqueId());
        $this->assertInstanceOf(InvoiceSuiteZfFxComfortProviderReader::class, $documentReader->getCurrentDocumentFormatProvider()->getReader());
    }

